#include <stdio.h>
#include <math.h>
#define W 2400
#define H 1800
typedef struct{float x,y,z;}V;
static V vc(float x,float y,float z){V r={x,y,z};return r;}
static V add(V a,V b){return vc(a.x+b.x,a.y+b.y,a.z+b.z);}
static V sub(V a,V b){return vc(a.x-b.x,a.y-b.y,a.z-b.z);}
static V mul(V a,float s){return vc(a.x*s,a.y*s,a.z*s);}
static float dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static V norm(V a){float l=(float)sqrt((double)dot(a,a));return vc(a.x/l,a.y/l,a.z/l);}
static V CEN;
static V LGT;
static float hitS(V ro,V rd){
 V oc=sub(ro,CEN);
 float a=dot(rd,rd),b=2.0f*dot(oc,rd),c=dot(oc,oc)-1.0f;
 float disc=b*b-4.0f*a*c;
 if(disc<0.0f)return -1.0f;
 double sq=sqrt((double)disc);
 float t=(float)(((double)(-b)-sq)/(double)(a+a));
 if(t>1e-3f)return t;
 t=(float)(((double)(-b)+sq)/(double)(a+a));
 if(t>1e-3f)return t;
 return -1.0f;
}
static float hitP(V ro,V rd){
 float d=rd.y; if(fabsf(d)<1e-4f)return -1.0f;
 float t=(-1.5f-ro.y)/d;
 if(t>1e-3f)return t;
 return -1.0f;
}
static int shadow(V p){return hitS(p,LGT)>0.0f;}
static V trace(V ro,V rd){
 float ts=hitS(ro,rd),tp=hitP(ro,rd);
 int hs=ts>0.0f,hp=tp>0.0f,issph;
 float t; V n;
 if(hs&&(!hp||ts<tp)){t=ts;issph=1;}
 else if(hp){t=tp;issph=0;}
 else{
  float u=0.5f*(rd.y+1.0f);
  return add(mul(vc(0.5f,0.7f,1.0f),u),mul(vc(1.0f,1.0f,1.0f),1.0f-u));
 }
 V pt=add(ro,mul(rd,t));
 if(issph)n=norm(sub(pt,CEN)); else n=vc(0.0f,1.0f,0.0f);
 float diff=(float)fmax(0.0,(double)dot(n,LGT));
 if(shadow(add(pt,mul(n,1e-3f))))diff=0.0f;
 float inten=(1.0f-0.2f)*diff+0.2f;
 V alb;
 if(issph)alb=vc(1.0f,0.2f,0.2f);
 else{
  int s=(int)(floor((double)pt.x)+floor((double)pt.z));
  float g=(s&1)?0.4f:0.9f;
  alb=vc(g,g,g);
 }
 return mul(alb,inten);
}
static int q(float c){
 float v=(float)fmin(fmax((double)c,0.0),1.0);
 return (int)(v*255.99f);
}
int main(void){
 CEN=vc(0.0f,-0.5f,-5.0f);
 LGT=norm(vc(1.0f,1.0f,-1.0f));
 float aspect=(float)W/(float)H;
 float vw=aspect*2.0f;
 V org=vc(0.0f,0.0f,0.0f);
 V hor=vc(vw,0.0f,0.0f);
 V ver=vc(0.0f,2.0f,0.0f);
 V ll=sub(sub(sub(org,mul(hor,0.5f)),mul(ver,0.5f)),vc(0.0f,0.0f,1.0f));
 FILE*f=fopen("reconstructed.ppm","w");
 fprintf(f,"P3\n%d %d\n255\n",W,H);
 for(int j=0;j<H;j++){
  for(int i=0;i<W;i++){
   float u=(float)i/(float)(W-1);
   float v=(float)j/(float)(H-1);
   V dir=add(add(mul(hor,u),sub(mul(ver,1.0f-v),org)),ll);
   dir=norm(dir);
   V col=trace(org,dir);
   fprintf(f,"%d %d %d\n",q(col.x),q(col.y),q(col.z));
  }
 }
 fclose(f);
 return 0;
}

